import { useEffect, useState } from "react";
import { io } from "socket.io-client";

function Room({ room, setPage }) {
  const [socket, setSocket] = useState(null);

  const [answer, setAnswer] = useState("");
  const [selected, setSelected] = useState([]);
  const [question, setQuestion] = useState(null);
  const [scores, setScores] = useState({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [role, setRole] = useState("participant");
  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);

  const [timerEnabled, setTimerEnabled] = useState(false);
  const [timeLimit, setTimeLimit] = useState(10);

  useEffect(() => {
    const newSocket = io("http://localhost:5000", {
      auth: {
        token: localStorage.getItem("token"),
      },
    });

    setSocket(newSocket);

    newSocket.on("role", (r) => {
      console.log("MY ROLE:", r);
      setRole(r);
    });

    newSocket.emit("join_room", {
      roomCode: room,
    });

    newSocket.on("receive_question", (q) => {
      setQuestion(q);
      setSelected([]);
      setAnswer("");
    });

    newSocket.on("timer_update", setTimeLeft);
    newSocket.on("update_scores", setScores);

    newSocket.on("quiz_finished", (s) => {
      alert("Квиз закончен!");
      console.log(s);
    });

    return () => newSocket.disconnect();
  }, [room]);

  const sendTextAnswer = () => {
    socket?.emit("submit_answer", {
      answer,
      roomCode: room,
    });
  };

  return (
    <div>
      {/* ВЫХОД */}
      <button
        onClick={() => {
          if (window.confirm("Выйти из комнаты?")) {
            setPage("dashboard");
          }
        }}
      >
        🚪 Выйти
      </button>

      <h2>Комната: {room}</h2>

      {/* ВОПРОС */}
      {question && (
        <div>
          {question.imageUrl && (
            <img src={question.imageUrl} width="200" alt="" />
          )}

          <h3>{question.text}</h3>

          {/* SINGLE / MULTIPLE */}
          {question.type !== "text" &&
            question.options.map((opt, i) => (
              <button
                key={i}
                onClick={() => {
                  if (question.type === "multiple") {
                    setSelected((prev) =>
                      prev.includes(opt)
                        ? prev.filter((o) => o !== opt)
                        : [...prev, opt]
                    );
                  } else {
                    socket?.emit("submit_answer", {
                      answer: opt,
                      roomCode: room,
                    });
                  }
                }}
                style={{
                  background: selected.includes(opt) ? "lightgreen" : "",
                }}
              >
                {opt}
              </button>
            ))}

          {/* MULTIPLE submit */}
          {question.type === "multiple" && (
            <button
              onClick={() =>
                socket?.emit("submit_answer", {
                  answer: selected,
                  roomCode: room,
                })
              }
            >
              Ответить
            </button>
          )}

          {/* TEXT */}
          {question.type === "text" && (
            <>
              <input
                value={answer}
                onChange={(e) => setAnswer(e.target.value)}
              />
              <button onClick={sendTextAnswer}>Ответить</button>
            </>
          )}
        </div>
      )}

      {/* ТАЙМЕР */}
      {timeLeft > 0 && <h2>⏱ Время: {timeLeft}</h2>}

      {/* ЛИДЕРБОРД */}
      <h3>🏆 Таблица</h3>
      {Object.entries(scores)
        .sort((a, b) => b[1].score - a[1].score)
        .map(([id, data], index) => (
          <div key={id}>
            {index + 1}. {data.name} — {data.score}
          </div>
        ))}

      {/* ОРГАНИЗАТОР */}
      {role === "organizer" && (
        <>
          <h3>⚙ Настройки</h3>

          <label>
            <input
              type="checkbox"
              onChange={(e) => setTimerEnabled(e.target.checked)}
            />
            Таймер
          </label>

          <input
            type="number"
            placeholder="сек"
            value={timeLimit}
            onChange={(e) => setTimeLimit(Number(e.target.value))}
          />

          <br />

          <button
            disabled={started}
            onClick={() => {
              socket?.emit("start_quiz", {
                roomCode: room,
                timerEnabled,
                timeLimit,
              });
              setStarted(true); // 👈 блокируем повторный старт
            }}
          >
            Старт квиза
          </button>

          <button
            onClick={() =>
              socket?.emit("next_question", { roomCode: room })
            }
          >
            ➡ Следующий
          </button>
        </>
      )}
    </div>
  );
}

export default Room;
